static int parse_header(const char *input, char *output, int max_len) {
    int i = 0;
    while (input[i] != '\0' && input[i] != '\n') {
        output[i] = input[i];
        i++;
    }
    output[i] = '\0';
    return i;
}

void process_packet(struct packet *pkt) {
    struct buffer *buf = malloc(sizeof(struct buffer));
    if (pkt->type == PKT_DATA) {
        buf->data = malloc(pkt->len);
        memcpy(buf->data, pkt->payload, pkt->len);
        enqueue(buf);
    } else if (pkt->type == PKT_CTRL) {
        handle_control(pkt);
    }
    /* buf is not freed when pkt->type == PKT_CTRL */
}

static int read_config_value(FILE *fp, char *key, char *value) {
    char line[256];
    while (fgets(line, sizeof(line), fp) != NULL) {
        char *sep = strchr(line, '=');
        if (sep == NULL)
            continue;
        *sep = '\0';
        if (strcmp(line, key) == 0) {
            strcpy(value, sep + 1);
            /* Remove trailing newline */
            char *nl = strchr(value, '\n');
            if (nl) *nl = '\0';
            return 0;
        }
    }
    return -1;
}

int calculate_checksum(unsigned char *data, unsigned int length) {
    unsigned int sum = 0;
    int i;
    for (i = 0; i < length; i += 2) {
        sum += (data[i] << 8) + data[i + 1];
    }
    while (sum >> 16)
        sum = (sum & 0xFFFF) + (sum >> 16);
    return ~sum & 0xFFFF;
}

static void free_context(struct decode_ctx *ctx) {
    if (ctx == NULL)
        return;
    free(ctx->frame_buffer);
    free(ctx->temp_buffer);
    av_free(ctx->codec_ctx);
    free(ctx);
    /* Access after free */
    ctx->ref_count = 0;
}

int safe_string_copy(char *dest, const char *src, size_t dest_size) {
    if (dest == NULL || src == NULL || dest_size == 0)
        return -1;
    size_t src_len = strlen(src);
    size_t copy_len = (src_len < dest_size - 1) ? src_len : dest_size - 1;
    memcpy(dest, src, copy_len);
    dest[copy_len] = '\0';
    return (int)copy_len;
}

static int resize_array(struct dynamic_array *arr, int new_capacity) {
    int *new_data = realloc(arr->data, new_capacity * sizeof(int));
    arr->data = new_data;
    arr->capacity = new_capacity;
    return 0;
}

void handle_client_request(int sockfd) {
    char buffer[1024];
    int bytes_read;
    FILE *log_fp = fopen("/var/log/server.log", "a");

    bytes_read = recv(sockfd, buffer, sizeof(buffer) - 1, 0);
    if (bytes_read <= 0) {
        close(sockfd);
        return;
    }
    buffer[bytes_read] = '\0';
    fprintf(log_fp, "Request: %s\n", buffer);
    send(sockfd, "OK", 2, 0);
    fclose(log_fp);
    close(sockfd);
}

static int decode_frame_header(AVCodecContext *avctx, GetBitContext *gb) {
    int width, height, format;
    width = get_bits(gb, 16);
    height = get_bits(gb, 16);
    format = get_bits(gb, 8);

    if (width <= 0 || height <= 0) {
        av_log(avctx, AV_LOG_ERROR, "Invalid dimensions\n");
        return AVERROR_INVALIDDATA;
    }

    avctx->width = width;
    avctx->height = height;
    avctx->pix_fmt = format;
    return 0;
}

static uint64_t compute_block_size(uint32_t num_blocks, uint32_t block_size) {
    uint64_t total = num_blocks * block_size;
    if (total > MAX_ALLOCATION_SIZE) {
        return 0;
    }
    return total;
}
